-- ========== schema-v19-descriptions-animals-skiing.sql ==========

-- ================================================================
-- schema-v19-descriptions-animals-skiing.sql
-- 챌린지 설명 확장: 500~1000자 (동물 9 + 스키 15)
-- ================================================================

-- ── ANIMALS (9) ─────────────────────────────────────────────────
UPDATE challenges SET description_en = 'Chimpanzees represent one of the most profound wildlife experiences on Earth—the legacy of Jane Goodall''s 60-year study. Observing our closest relatives (98.7% shared DNA) in the wild reveals tool use, hunting parties, complex politics, and emotional bonds. Forested habitats in equatorial Africa offer opportunities to encounter habituated troops. Selected for our World 100 as the definitive primate encounter and a living link to our evolutionary past.' WHERE category = 'animals' AND title_en = 'Chimpanzee';

UPDATE challenges SET description_en = 'Great white shark cage diving lets you encounter the ocean''s 6-meter apex predator in its realm. These animals breach up to 4 meters, possess electroreceptive ampullae that detect prey, and represent 400 million years of evolution. The experience combines adrenaline with conservation education. Selected for our World 100 as the most accessible and responsible way to witness the planet''s most iconic shark.' WHERE category = 'animals' AND title_en = 'Great White Shark';

UPDATE challenges SET description_en = 'The Cape buffalo is one of Africa''s Big Five and among the most dangerous animals on the continent—unpredictable, social, and capable of charging at 57 km/h. Weighing up to 900 kg, these animals have killed more big-game hunters than any other African species. On savanna reserves they form herds of hundreds. Selected for our World 100 as the ultimate symbol of untamed African wilderness.' WHERE category = 'animals' AND title_en = 'Cape Buffalo';

UPDATE challenges SET description_en = 'The three-toed sloth embodies a unique way of life: sleeping 20 hours daily, moving so slowly that algae grows in its fur (providing camouflage), and spending its life upside down. This arboreal mammal has evolved to conserve energy in nutrient-poor rainforest canopies in the Neotropics. Selected for our World 100 as one of the most charismatic and emblematic species of the Americas.' WHERE category = 'animals' AND title_en = 'Three-toed Sloth';

UPDATE challenges SET description_en = 'Atlantic puffins—the "clown of the sea" with their colorful beaks and comical gait—number around 60 million globally. These birds dive 60 meters for fish and can carry 10 sand eels at once. Summer breeding colonies in the North Atlantic offer close encounters. Selected for our World 100 as one of the most accessible and photogenic seabird experiences on Earth.' WHERE category = 'animals' AND title_en = 'Atlantic Puffin';

UPDATE challenges SET description_en = 'The fennec fox is the world''s smallest fox (1.5 kg) and a master of Sahara survival. Its enormous 15 cm ears radiate heat and detect prey underground; it hunts at night when the desert cools. Desert encounters reveal an elusive, adorable predator. Selected for our World 100 as the most charismatic desert mammal and a symbol of adaptation to extreme environments.' WHERE category = 'animals' AND title_en = 'Fennec Fox';

UPDATE challenges SET description_en = 'The Amur tiger is the world''s largest cat—males reach 300 kg—and one of the most endangered, with only about 500 remaining in the wild. Cold temperate forests in Siberia and the Far East are their last stronghold. Selected for our World 100 as the rarest and most majestic big cat encounter on the planet.' WHERE category = 'animals' AND title_en = 'Amur Tiger';

UPDATE challenges SET description_en = 'Schools of hundreds of scalloped hammerhead sharks are one of the world''s most spectacular underwater phenomena. Their unique head shape provides 360° vision and electromagnetic prey detection. Drift dives through these aggregations are unforgettable in suitable Pacific and tropical waters. Selected for our World 100 as the definitive hammerhead encounter.' WHERE category = 'animals' AND title_en = 'Scalloped Hammerhead Shark';

UPDATE challenges SET description_en = 'The golden snub-nosed monkey is a blue-faced, golden-orange primate that lives in temperate mountain forests and survives -20°C winters at high altitude. These endangered monkeys live in troops of hundreds and are a conservation icon. Selected for our World 100 as one of Asia''s most striking and rarely seen primates.' WHERE category = 'animals' AND title_en = 'Golden Snub-nosed Monkey';

-- ── SKIING (15) ─────────────────────────────────────────────────
UPDATE challenges SET description_en = 'St. Moritz invented winter tourism and hosted the Winter Olympics in 1928 and 1948. The Engadine valley resort offers the legendary Cresta Run bobsled, world-class skiing, and a concentration of luxury hotels and Michelin stars unmatched in the Alps. Selected for our World 100 as the birthplace of Alpine winter luxury and the most prestigious ski destination on Earth.' WHERE category = 'skiing' AND title_en = 'St Moritz';

UPDATE challenges SET description_en = 'Alpe d''Huez in the French Alps offers 245 km of pistes and the famous 21 hairpin bends of the Tour de France. The Sarenne run is one of the world''s longest glacier descents at 16 km. Sunny exposure and varied terrain make it a favorite for intermediate and advanced skiers. Selected for our World 100 as the quintessential French mega-resort with cycling and skiing heritage.' WHERE category = 'skiing' AND title_en = 'Alpe d''Huez';

UPDATE challenges SET description_en = 'Tignes guarantees snow from 3,456 m altitude and links with Val d''Isère to form the vast Espace Killy. The Grande Motte glacier enables summer skiing. Modern infrastructure and high-altitude villages make Tignes a reliable choice for early and late season. Selected for our World 100 as France''s highest major resort and the gateway to endless Alpine terrain.' WHERE category = 'skiing' AND title_en = 'Tignes';

UPDATE challenges SET description_en = 'Megève was developed by the Rothschild family as an elegant alternative to St. Moritz—a Haute-Savoie village with horse-drawn sleighs, gourmet restaurants, and 445 km of linked skiing via the Evasion Mont-Blanc area. Selected for our World 100 as the most refined French Alpine village and a gastronomic ski destination.' WHERE category = 'skiing' AND title_en = 'Megève';

UPDATE challenges SET description_en = 'Saas-Fee is a car-free Swiss village surrounded by 4,000 m peaks, with year-round skiing on the Mittelallalin glacier at 3,500 m. The Alpin Express underground funicular accesses the highest ski area in the Alps. Selected for our World 100 as the most magical glacier village and a summer skiing paradise.' WHERE category = 'skiing' AND title_en = 'Saas-Fee';

UPDATE challenges SET description_en = 'Flims Laax is Switzerland''s snowboard capital, home to Europe''s largest halfpipe and the Crap Sogn Gion summit. The area links with Disentis for 224 km of varied terrain. Selected for our World 100 as the premier freestyle and park skiing destination in the Alps.' WHERE category = 'skiing' AND title_en = 'Flims Laax';

UPDATE challenges SET description_en = 'Saalbach-Hinterglemm forms the "Ski Circus"—270 km of connected pistes with Leogang and Fieberbrunn. The après-ski at Hinterhagalm is legendary. Selected for our World 100 as Austria''s most complete ski circuit and the ultimate Alpine party-and-piste combination.' WHERE category = 'skiing' AND title_en = 'Saalbach-Hinterglemm';

UPDATE challenges SET description_en = 'Kronplatz (Plan de Corones) in South Tyrol is a World Cup super-G venue with 32 lifts and 119 km of runs. The summit offers 360° views of the Dolomites. Selected for our World 100 as the most dramatic single-mountain ski experience in the Dolomites.' WHERE category = 'skiing' AND title_en = 'Kronplatz, South Tyrol';

UPDATE challenges SET description_en = 'Baqueira-Beret in the Spanish Pyrenees is the Spanish Royal family''s resort and the largest ski area in Spain (166 km). The Val d''Aran villages preserve Catalan culture. Selected for our World 100 as Spain''s premier ski destination and a gateway to Pyrenean charm.' WHERE category = 'skiing' AND title_en = 'Baqueira-Beret';

UPDATE challenges SET description_en = 'Geilo is Norway''s most popular ski resort, set on the Hardangervidda plateau between Oslo and Bergen. Husky sledding, cabin culture, and reliable snow define the experience. Selected for our World 100 as the quintessential Norwegian winter destination.' WHERE category = 'skiing' AND title_en = 'Geilo';

UPDATE challenges SET description_en = 'Breckenridge rises to 3,903 m (12,998 ft)—one of Colorado''s highest ski resorts. The historic gold-mining town offers 187 runs across five peaks and a vibrant Main Street. Selected for our World 100 as the perfect blend of American ski terrain and Old West character.' WHERE category = 'skiing' AND title_en = 'Breckenridge';

UPDATE challenges SET description_en = 'Stowe is Vermont''s oldest and most prestigious resort, with Mt. Mansfield (1,339 m) offering classic New England skiing and a charming village. Selected for our World 100 as the soul of East Coast skiing and the birthplace of American ski culture.' WHERE category = 'skiing' AND title_en = 'Stowe';

UPDATE challenges SET description_en = 'Revelstoke in British Columbia boasts the greatest vertical drop of any ski resort in North America (1,713 m). It is the heli-ski and cat-skiing capital of the world. Selected for our World 100 as the ultimate destination for deep powder and extreme terrain.' WHERE category = 'skiing' AND title_en = 'Revelstoke';

UPDATE challenges SET description_en = 'Mt. Buller is Victoria''s largest ski area, three hours from Melbourne, with 180 km of runs and host to Australian Alpine championships. Selected for our World 100 as the most accessible major Australian ski resort and the heart of Victorian snow culture.' WHERE category = 'skiing' AND title_en = 'Mt Buller';

UPDATE challenges SET description_en = 'Killington is the largest ski resort in the eastern United States—155 runs, the longest season in North America, and the beastly K1 Express gondola. Selected for our World 100 as the East Coast''s most ambitious resort and a snowmaking pioneer.' WHERE category = 'skiing' AND title_en = 'Killington';

-- ================================================================
-- 완료: Animals 9 + Skiing 15 = 24개
-- ================================================================



-- ========== schema-v19-descriptions-fishing.sql ==========

-- ================================================================
-- schema-v19-descriptions-fishing.sql — 100 Fishing Spots (500~1000자)
-- ================================================================

UPDATE challenges SET description_en = 'The Kenai River in Alaska holds the world record for king salmon (44 kg) and is the most famous salmon river in North America. July sees "combat fishing" at Soldotna where anglers line the banks for migrating kings. The river''s glacial turquoise waters flow through pristine wilderness with mountain backdrops. Selected for our World 100 as the definitive Alaskan salmon experience and a bucket-list destination for every angler.' WHERE category = 'fishing' AND title_en = 'Kenai River';

UPDATE challenges SET description_en = 'British Columbia''s Skeena River is the holy grail of fly fishing—wild steelhead to 15 kg in untouched wilderness. Float trips from Terrace descend through cedar forests and crystal waters. The Skeena system represents the pinnacle of Pacific steelhead culture and catch-and-release ethics. Selected for our World 100 as the greatest wild steelhead river on Earth.' WHERE category = 'fishing' AND title_en = 'Skeena River';

UPDATE challenges SET description_en = 'Quebec''s Grand Cascapedia River is legendary for Atlantic salmon—fish over 40 lb are not uncommon on private beats. Traditional canoe and guide culture, strict conservation, and the river''s remote Gaspé setting make it the crown jewel of North American salmon fishing. Selected for our World 100 as the most exclusive and storied Atlantic salmon river.' WHERE category = 'fishing' AND title_en = 'Grand Cascapedia River';

UPDATE challenges SET description_en = 'The Florida Keys offer the Grand Slam: tarpon, permit, and bonefish in the same day on the flats. This is the Mecca of saltwater fly fishing, with year-round opportunities, legendary guides, and the most technical sight-fishing on the planet. Selected for our World 100 as the ultimate saltwater flats destination.' WHERE category = 'fishing' AND title_en = 'Florida Keys';

UPDATE challenges SET description_en = 'Kona on Hawaii''s Big Island is the Pacific blue marlin capital—1,000 lb fish are targeted in the annual International Billfish Tournament. The deep water close to shore and consistent currents create ideal conditions. Selected for our World 100 as the world''s premier blue marlin fishery.' WHERE category = 'fishing' AND title_en = 'Kona, Hawaii';

UPDATE challenges SET description_en = 'Andros Island in the Bahamas is the bonefish Mecca—100 miles of shallow sand flats with tailing fish. The birthplace of modern bonefishing, it offers the finest flats in the Atlantic and a tradition of expert guides. Selected for our World 100 as the definitive bonefish destination.' WHERE category = 'fishing' AND title_en = 'Andros Island, Bahamas';

UPDATE challenges SET description_en = 'Jardines de la Reina off Cuba is a Grand Slam paradise: permit, tarpon, and bonefish in pristine reef waters, often in one day. Access is by live-aboard only, preserving one of the Caribbean''s last untouched fisheries. Selected for our World 100 as the most pristine Caribbean flats and reef fishery.' WHERE category = 'fishing' AND title_en = 'Jardines de la Reina, Cuba';

UPDATE challenges SET description_en = 'Pinas Bay in Panama hosts world records for black marlin and Pacific sailfish. Tropic Star Lodge has defined Central American big-game fishing for decades. The Darién coast offers unmatched billfish action. Selected for our World 100 as the most famous big-game lodge and sailfish capital.' WHERE category = 'fishing' AND title_en = 'Pinas Bay, Panama';

UPDATE challenges SET description_en = 'Iztapa on Guatemala''s Pacific coast holds world records for Pacific sailfish releases—50 or more fish per day in season. Sailfish Oasis and the local fleet have made it the sailfish release capital of the world. Selected for our World 100 as the greatest sailfish fishery on Earth.' WHERE category = 'fishing' AND title_en = 'Iztapa, Guatemala';

UPDATE challenges SET description_en = 'Argentina''s Rio Grande in Tierra del Fuego holds the world record for sea-run brown trout (36 kg). Wind-swept Patagonian rivers, January through March, offer the ultimate brown trout pilgrimage. Selected for our World 100 as the greatest sea-trout river in the world.' WHERE category = 'fishing' AND title_en = 'Rio Grande, Tierra del Fuego';

UPDATE challenges SET description_en = 'Chile''s Palena River in remote Patagonia offers wild rainbow trout in the Aysén wilderness. Helicopter access lodges provide fishing in rivers that see fewer anglers in a year than some rivers see in a day. Selected for our World 100 as the most remote and pristine Patagonian trout experience.' WHERE category = 'fishing' AND title_en = 'Palena River, Chile';

UPDATE challenges SET description_en = 'Venezuela''s Cinaruco River in the Apure Llanos is home to the payara—the "vampire fish" with 4-inch fangs. This sabre-tooth predator reaches 25 lb and attacks surface lures with explosive strikes. Selected for our World 100 as the most dramatic and prehistoric freshwater gamefish.' WHERE category = 'fishing' AND title_en = 'Cinaruco River, Venezuela';

UPDATE challenges SET description_en = 'Colombia''s Inirida River in the Guainía system is world-record peacock bass habitat. Remote Amazon tributaries hold massive tucunaré in untouched jungle. Selected for our World 100 as the ultimate Amazon peacock bass destination.' WHERE category = 'fishing' AND title_en = 'Inirida River, Colombia';

UPDATE challenges SET description_en = 'Norway''s Alta River in Finnmark is considered the world''s greatest Atlantic salmon river—50 lb salmon are the dream. Midnight sun, strict fly-only beats, and generations of tradition define the Alta. Selected for our World 100 as the king of salmon rivers.' WHERE category = 'fishing' AND title_en = 'Alta River, Norway';

UPDATE challenges SET description_en = 'Spain''s Canary Islands see 500 kg Atlantic bluefin tuna migrate through El Hierro waters January–March. Giant bluefin on stand-up tackle in volcanic island waters is a unique Atlantic experience. Selected for our World 100 as Europe''s premier bluefin tuna fishery.' WHERE category = 'fishing' AND title_en = 'Canary Islands, Spain';

UPDATE challenges SET description_en = 'The Azores in the mid-Atlantic offer bluefin tuna and blue marlin in July—world-class big game from volcanic islands. The mix of species and the dramatic geography make the Azores a unique Atlantic destination. Selected for our World 100 as the mid-Atlantic big-game capital.' WHERE category = 'fishing' AND title_en = 'Azores, Portugal';

UPDATE challenges SET description_en = 'Russia''s Kola Peninsula—Varzuga, Yokanga, and other rivers—is Atlantic salmon paradise. Prolific runs from June to August, helicopter lodges, and wilderness scale define the Kola. Selected for our World 100 as the greatest concentration of wild Atlantic salmon on Earth.' WHERE category = 'fishing' AND title_en = 'Kola Peninsula, Russia';

UPDATE challenges SET description_en = 'The Ponoi River on the Kola Peninsula has the highest Atlantic salmon catch per rod of any river. Remote wilderness, helicopter access, and exceptional lodge operations make it the ultimate salmon trip. Selected for our World 100 as the most prolific salmon river per angler.' WHERE category = 'fishing' AND title_en = 'Ponoi River, Russia';

UPDATE challenges SET description_en = 'The Congo River in the DRC holds the goliath tigerfish—50 kg of prehistoric predator with razor teeth. Malebo Pool and the rapids offer the most extreme freshwater fishing on the planet. Selected for our World 100 as the ultimate river monster destination.' WHERE category = 'fishing' AND title_en = 'Congo River, DRC';

UPDATE challenges SET description_en = 'Seychelles'' Cosmoledo Atoll offers giant trevally on fly—40 kg GT hunting shallow flats in a pristine Indian Ocean atoll. Remote, fly-in only, and with minimal pressure, Cosmoledo is GT heaven. Selected for our World 100 as the finest GT on fly destination.' WHERE category = 'fishing' AND title_en = 'Cosmoledo Atoll, Seychelles';

UPDATE challenges SET description_en = 'Russia''s Kamchatka Peninsula has six species of Pacific salmon in untouched rivers. Helicopter lodges access wilderness that has never been overfished. Selected for our World 100 as the last great Pacific salmon frontier.' WHERE category = 'fishing' AND title_en = 'Kamchatka Peninsula, Russia';

UPDATE challenges SET description_en = 'The Yarlung Tsangpo in Tibet is the world''s highest major river—fishing at 4,000 m for snow trout and Himalayan mahseer. The "roof of the world" offers a unique high-altitude fishery. Selected for our World 100 as the most dramatic high-elevation fishing experience.' WHERE category = 'fishing' AND title_en = 'Yarlung Tsangpo, Tibet';

UPDATE challenges SET description_en = 'Mongolia''s Eg-Uur River holds the world''s largest salmonid—the taimen, to 60 kg and more. Horseback access, catch-and-release only, and pristine wilderness define this once-in-a-lifetime fishery. Selected for our World 100 as the ultimate taimen destination.' WHERE category = 'fishing' AND title_en = 'Eg-Uur River, Mongolia';

UPDATE challenges SET description_en = 'Thailand''s Chiang Khong on the Mekong was home to the world record Mekong giant catfish (293 kg). The species is critically endangered; the northern Thailand Mekong remains iconic. Selected for our World 100 as the legendary home of the giant catfish.' WHERE category = 'fishing' AND title_en = 'Chiang Khong, Thailand';

UPDATE challenges SET description_en = 'Papua''s Mamberamo River offers black bass and other species in untouched Indonesian wilderness. Fly-in-only access to remote rivers makes it one of the last frontiers of freshwater fishing. Selected for our World 100 as the most remote tropical river fishery.' WHERE category = 'fishing' AND title_en = 'Mamberamo River, Papua';

UPDATE challenges SET description_en = 'Montana''s Madison River is a blue-ribbon trout stream with over 3,000 trout per mile. The Yellowstone gateway offers classic nymph and dry-fly fishing in one of America''s most iconic rivers. Selected for our World 100 as the quintessential Western trout river.' WHERE category = 'fishing' AND title_en = 'Madison River, Montana';

UPDATE challenges SET description_en = 'The Bighorn River in Montana is a trophy tailwater below Yellowtail Dam—20-inch browns and rainbows are common. Crow Agency and Fort Smith offer world-class drift boat fishing. Selected for our World 100 as America''s finest tailwater trout fishery.' WHERE category = 'fishing' AND title_en = 'Bighorn River, Montana';

UPDATE challenges SET description_en = 'Oregon''s Deschutes River offers premier summer steelhead and trout through high-desert canyon. Maupin and the lower Deschutes define Pacific Northwest steelhead culture. Selected for our World 100 as one of the West''s greatest steelhead rivers.' WHERE category = 'fishing' AND title_en = 'Deschutes River, Oregon';

UPDATE challenges SET description_en = 'Wyoming''s Green River below Flaming Gorge Dam is a blue-ribbon tailwater with trophy rainbow and brown trout. Seedskadee and the upper Green offer diverse waters. Selected for our World 100 as the premier tailwater of the Rocky Mountains.' WHERE category = 'fishing' AND title_en = 'Green River, Wyoming';

UPDATE challenges SET description_en = 'New Mexico''s San Juan River below Navajo Dam produces 20-inch plus rainbows with legendary consistency. Quality fly-fishing waters near Aztec make it a year-round destination. Selected for our World 100 as the finest tailwater in the American Southwest.' WHERE category = 'fishing' AND title_en = 'San Juan River, New Mexico';

UPDATE challenges SET description_en = 'Alaska''s Naknek River and Bristol Bay host the world''s largest sockeye salmon run each July. King salmon add to the diversity in this legendary Alaskan fishery. Selected for our World 100 as the heart of the greatest sockeye run on Earth.' WHERE category = 'fishing' AND title_en = 'Naknek River, Alaska';

UPDATE challenges SET description_en = 'Idaho''s Snake River offers wild steelhead and chinook salmon; the Hell''s Canyon stretch is legendary. September through January brings steelhead into the system. Selected for our World 100 as the premier Snake River steelhead fishery.' WHERE category = 'fishing' AND title_en = 'Snake River, Idaho';

UPDATE challenges SET description_en = 'Alberta''s Bow River flows through Calgary and holds world-class brown and rainbow trout. October is prime for drift boat fishing in one of North America''s best urban trout rivers. Selected for our World 100 as the finest city trout river in the world.' WHERE category = 'fishing' AND title_en = 'Bow River, Alberta';

UPDATE challenges SET description_en = 'New Brunswick''s Miramichi River is Atlantic salmon heartland—the crown jewel of Canadian salmon fishing. Summer and fall runs draw anglers from every continent. Selected for our World 100 as Canada''s greatest Atlantic salmon river.' WHERE category = 'fishing' AND title_en = 'Miramichi River, New Brunswick';

UPDATE challenges SET description_en = 'Ontario''s Nipigon River held the world record brook trout (6.57 lb, 1915). The remote Lake Nipigon system still offers exceptional brookie and fly-in access. Selected for our World 100 as the legendary home of trophy brook trout.' WHERE category = 'fishing' AND title_en = 'Nipigon River, Ontario';

UPDATE challenges SET description_en = 'Boca Grande Pass in Florida is the tarpon capital—June sees 200 lb fish schooling through the pass. Snook, cobia, and grouper add to the diversity. Selected for our World 100 as the world''s greatest tarpon migration fishery.' WHERE category = 'fishing' AND title_en = 'Boca Grande Pass, Florida';

UPDATE challenges SET description_en = 'Cape Cod in Massachusetts is a striped bass surfcasting classic; Montauk Point and the fall migration bring blitzes of bass and bluefish. Selected for our World 100 as the East Coast''s premier striper destination.' WHERE category = 'fishing' AND title_en = 'Cape Cod, Massachusetts';

UPDATE challenges SET description_en = 'Florida''s Everglades offer snook and redfish in the backcountry; Ten Thousand Islands and kayak fishing define the experience. Selected for our World 100 as the ultimate subtropical inshore fishery.' WHERE category = 'fishing' AND title_en = 'Everglades, Florida';

UPDATE challenges SET description_en = 'Cabo San Lucas in Mexico is a striped marlin and dorado corridor November–April. The Pisces Fleet and Baja California waters are billfish legends. Selected for our World 100 as the Pacific''s most accessible marlin capital.' WHERE category = 'fishing' AND title_en = 'Cabo San Lucas, Mexico';

UPDATE challenges SET description_en = 'Cozumel in Mexico offers Atlantic blue marlin in the Caribbean—600–800 lb fish in July–September. Deep blue water and Cozumel''s reefs make it a unique Caribbean big-game destination. Selected for our World 100 as the Caribbean''s premier blue marlin fishery.' WHERE category = 'fishing' AND title_en = 'Cozumel, Mexico';

UPDATE challenges SET description_en = 'Puerto Vallarta sees Pacific sailfish peak November–January; striped marlin and dorado at El Morro Bank. Mexico''s Pacific coast offers world-class billfish. Selected for our World 100 as the finest Pacific Mexico sailfish fishery.' WHERE category = 'fishing' AND title_en = 'Puerto Vallarta, Mexico';

UPDATE challenges SET description_en = 'Argentina''s Corrientes Province holds golden dorado—acrobatic game fish in the Rio Pirapo and tributaries. Electric gold in fast water defines this iconic South American species. Selected for our World 100 as the greatest dorado fishery on Earth.' WHERE category = 'fishing' AND title_en = 'Corrientes Province, Argentina';

UPDATE challenges SET description_en = 'Brazil''s Amazon River offers peacock bass and pirarucu from jungle lodges. The world''s most prized freshwater gamefish in the world''s greatest river. Selected for our World 100 as the ultimate Amazon fishing experience.' WHERE category = 'fishing' AND title_en = 'Amazon River, Brazil';

UPDATE challenges SET description_en = 'Brazil''s Pantanal—the world''s largest wetland—holds golden dorado, piranha, and tucunare. Corumbá accessibility and lodge-based fishing make it the gateway to this legendary fishery. Selected for our World 100 as the greatest wetland fishery on the planet.' WHERE category = 'fishing' AND title_en = 'Pantanal, Brazil';

UPDATE challenges SET description_en = 'Costa Rica''s Guanacaste coast offers roosterfish—a unique Pacific game fish with a dramatic dorsal fin. Nosara and Samara Peninsula are the heart of roosterfish country. Selected for our World 100 as the premier roosterfish destination.' WHERE category = 'fishing' AND title_en = 'Guanacaste, Costa Rica';

UPDATE challenges SET description_en = 'Peru''s Madre de Dios River in the Amazon holds peacock bass in remote jungle; Inkaterra and other lodges offer record tucunaré on fly. Selected for our World 100 as the finest Amazon lodge-based peacock fishery.' WHERE category = 'fishing' AND title_en = 'Madre de Dios River, Peru';

UPDATE challenges SET description_en = 'Argentina''s Paraná River—South America''s second longest—holds golden dorado and surubi catfish. Entre Ríos province offers diverse and prolific fishing. Selected for our World 100 as one of South America''s greatest river systems.' WHERE category = 'fishing' AND title_en = 'Parana River, Argentina';

UPDATE challenges SET description_en = 'Norway''s Lofoten Islands offer Arctic cod and coalfish from traditional wooden boats. Henningsvær and Svolvær provide winter drama and Nordic fishing culture. Selected for our World 100 as the most dramatic cold-water island fishery.' WHERE category = 'fishing' AND title_en = 'Lofoten Islands, Norway';

UPDATE challenges SET description_en = 'Iceland''s Ellidaár River runs through Reykjavík—wild Atlantic salmon through the capital. June–September offer urban salmon fishing in a unique setting. Selected for our World 100 as the only major capital with a world-class salmon river.' WHERE category = 'fishing' AND title_en = 'Ellidaár River, Iceland';

UPDATE challenges SET description_en = 'Iceland''s Tungnaá River in the highlands offers remote salmon fishing; the Tungnafjöt system peaks in August. Wilderness camps and minimal pressure define the experience. Selected for our World 100 as Iceland''s finest wilderness salmon river.' WHERE category = 'fishing' AND title_en = 'Tungnaá River, Iceland';

UPDATE challenges SET description_en = 'Scotland''s River Tay is the premier Scottish salmon river—Kenmore and Aberfeldy beats hold spring salmon and historical records. Selected for our World 100 as Scotland''s greatest salmon river.' WHERE category = 'fishing' AND title_en = 'River Tay, Scotland';

UPDATE challenges SET description_en = 'Scotland''s River Spey is the birthplace of Spey casting; Grantown-on-Spey and Ballindalloch sit in whisky country. The Spey defines Scottish salmon fishing. Selected for our World 100 as the most iconic Scottish salmon river.' WHERE category = 'fishing' AND title_en = 'River Spey, Scotland';

UPDATE challenges SET description_en = 'The River Tweed on the Scotland–England border is an Atlantic salmon powerhouse—Kelso and Berwick beats peak in autumn. Selected for our World 100 as the greatest border salmon river.' WHERE category = 'fishing' AND title_en = 'River Tweed, Scotland';

UPDATE challenges SET description_en = 'Spain''s Ebro River holds European wels catfish to 100 kg and more. The Mequinenza reservoir is the monster catfish capital of Europe. Selected for our World 100 as the world''s greatest catfish fishery.' WHERE category = 'fishing' AND title_en = 'Ebro River, Spain';

UPDATE challenges SET description_en = 'India''s Ramganga River in Jim Corbett National Park holds golden mahseer to 50 kg—the sacred fish and India''s greatest freshwater gamefish. Uttarakhand offers a unique cultural and angling experience. Selected for our World 100 as the definitive mahseer destination.' WHERE category = 'fishing' AND title_en = 'Ramganga River, India';

UPDATE challenges SET description_en = 'India''s Cauvery River offers mahseer on fly—humpback mahseer in Karnataka and Tamil Nadu. Galibore camp is a classic. Selected for our World 100 as India''s premier fly-fishing mahseer river.' WHERE category = 'fishing' AND title_en = 'Cauvery River, India';

UPDATE challenges SET description_en = 'Japan''s Hokkaido holds itou (Japanese taimen) over 1 m and wild brown trout. Shiretoko UNESCO rivers offer pristine wilderness fishing. Selected for our World 100 as Asia''s finest wild salmonid fishery.' WHERE category = 'fishing' AND title_en = 'Hokkaido, Japan';

UPDATE challenges SET description_en = 'Malaysian Borneo''s Sarawak offers toman (giant snakehead), belida, and sebarau in Batang Ai jungle lakes. Unique species and rainforest setting define this fishery. Selected for our World 100 as the premier Borneo jungle fishing destination.' WHERE category = 'fishing' AND title_en = 'Sarawak, Borneo, Malaysia';

UPDATE challenges SET description_en = 'The Zambezi River below Victoria Falls on the Zimbabwe–Zambia border holds tigerfish in rapids and pools. September is prime for this iconic African gamefish. Selected for our World 100 as the greatest tigerfish fishery in Africa.' WHERE category = 'fishing' AND title_en = 'Zambezi River, Zimbabwe';

UPDATE challenges SET description_en = 'Lake Tanganyika is the world''s longest and deepest lake—Nile perch, tigerfish, and the Mahale Mountains backdrop. Kigoma in Tanzania offers a unique East African fishery. Selected for our World 100 as the most dramatic Rift Valley lake fishery.' WHERE category = 'fishing' AND title_en = 'Lake Tanganyika, Tanzania';

UPDATE challenges SET description_en = 'Mozambique''s Bazaruto Archipelago offers sailfish, blue marlin, and giant trevally from Inhambane. Indian Ocean offshore and reef fishing in a pristine setting. Selected for our World 100 as East Africa''s premier offshore destination.' WHERE category = 'fishing' AND title_en = 'Bazaruto Archipelago, Mozambique';

UPDATE challenges SET description_en = 'Watamu on Kenya''s coast is the billfish capital—March–April striped marlin and the Watamu Marine Park. Grouper and other reef species add diversity. Selected for our World 100 as Kenya''s finest billfish and reef fishery.' WHERE category = 'fishing' AND title_en = 'Watamu, Kenya';

UPDATE challenges SET description_en = 'The Zanzibar Channel at the Indo-Pacific meeting point holds blue marlin and yellowfin tuna. Pemba Island offshore offers trophy fishing. Selected for our World 100 as the premier Tanzania offshore fishery.' WHERE category = 'fishing' AND title_en = 'Zanzibar Channel, Tanzania';

UPDATE challenges SET description_en = 'Malindi Marine Reserve in Kenya sees striped marlin and sailfish peak March–April. Prime season and accessible coast make it a key Kenyan destination. Selected for our World 100 as Kenya''s sailfish capital.' WHERE category = 'fishing' AND title_en = 'Malindi, Kenya';

UPDATE challenges SET description_en = 'Lake Baikal—the world''s deepest lake—offers Baikal omul ice fishing, taimen, and giant grayling. Listvyanka and winter fishing are legendary. Selected for our World 100 as the most unique Siberian freshwater fishery.' WHERE category = 'fishing' AND title_en = 'Lake Baikal, Russia';

UPDATE challenges SET description_en = 'The Amur River on the Russia–China border holds itou salmon to 100 kg and taimen. Extreme remoteness and unique species define this frontier. Selected for our World 100 as the most extreme Asian river fishery.' WHERE category = 'fishing' AND title_en = 'Amur River, Russia';

UPDATE challenges SET description_en = 'Japan''s Shiretoko Peninsula—UNESCO wilderness—holds wild itou salmon. Permit fishing and bear-watching combine in a unique experience. Selected for our World 100 as Japan''s finest wilderness salmonid destination.' WHERE category = 'fishing' AND title_en = 'Shiretoko Peninsula, Japan';

UPDATE challenges SET description_en = 'Fiji''s Yasawa Islands offer giant trevally on popping gear—remote islands, coral, and bluewater variety. Selected for our World 100 as the premier South Pacific GT and reef fishery.' WHERE category = 'fishing' AND title_en = 'Yasawa Islands, Fiji';

UPDATE challenges SET description_en = 'Palau in Micronesia offers dogtooth tuna jigging and GT at Ngemelis Wall and Blue Corner. Pristine Pacific bluewater and unique geography. Selected for our World 100 as Micronesia''s finest bluewater destination.' WHERE category = 'fishing' AND title_en = 'Palau, Micronesia';

UPDATE challenges SET description_en = 'Mauritius in the Indian Ocean holds blue marlin and yellowfin tuna records. Le Morne peninsula is the base for IGFA-class fishing. Selected for our World 100 as the Indian Ocean''s premier big-game island.' WHERE category = 'fishing' AND title_en = 'Mauritius';

UPDATE challenges SET description_en = 'The Maldives offer giant trevally, wahoo, and bonefish on pristine atolls. Popping, jigging, and flats fishing in one archipelago. Selected for our World 100 as the ultimate Indian Ocean multi-species destination.' WHERE category = 'fishing' AND title_en = 'Maldives';

UPDATE challenges SET description_en = 'Oman''s Musandam Peninsula offers dogtooth tuna and GT jigging in the Arabian Sea. Grouper and amberjack add to the mix in dramatic fjord scenery. Selected for our World 100 as the Arabian Peninsula''s premier offshore fishery.' WHERE category = 'fishing' AND title_en = 'Musandam Fjords, Oman';

UPDATE challenges SET description_en = 'The Solomon Islands offer remote Melanesian GT popping—Munda, Ghizo, Marovo Lagoon. Untouched Pacific islands and minimal pressure. Selected for our World 100 as the most remote Pacific island fishery.' WHERE category = 'fishing' AND title_en = 'Solomon Islands';

UPDATE challenges SET description_en = 'Papua New Guinea holds black bass and giant trevally at Cape Vogel and Madang. Remote PNG and pristine reefs define the experience. Selected for our World 100 as the last frontier of Pacific reef fishing.' WHERE category = 'fishing' AND title_en = 'Papua New Guinea';

UPDATE challenges SET description_en = 'Lake Erie is the walleye capital of the world—Great Lakes trophy walleye, perch, and smallmouth bass. Ohio and the islands are the heart of the fishery. Selected for our World 100 as the greatest walleye fishery on Earth.' WHERE category = 'fishing' AND title_en = 'Lake Erie, USA';

UPDATE challenges SET description_en = 'Minnesota''s Boundary Waters offer wilderness canoe fishing—walleye, muskie, northern pike in the northwoods. BWCA permit and Canada border lakes. Selected for our World 100 as the premier wilderness canoe fishery.' WHERE category = 'fishing' AND title_en = 'Boundary Waters, Minnesota';

UPDATE challenges SET description_en = 'Chesapeake Bay in Maryland is the largest estuary in the USA—striped bass, blue crab, and rockfish surfcasting. A classic American fishery. Selected for our World 100 as the greatest estuary fishery in North America.' WHERE category = 'fishing' AND title_en = 'Chesapeake Bay, Maryland';

UPDATE challenges SET description_en = 'Louisiana''s bayous offer red drum and speckled trout in Cajun marsh country. Atchafalaya Basin and the coast define inshore fishing. Selected for our World 100 as the ultimate marsh and bayou fishery.' WHERE category = 'fishing' AND title_en = 'Louisiana Bayou, USA';

UPDATE challenges SET description_en = 'Panama''s Bocas del Toro offers Atlantic tarpon in Caribbean lagoons—snook, jack, and archipelago fishing. Selected for our World 100 as the premier Caribbean tarpon destination in Central America.' WHERE category = 'fishing' AND title_en = 'Bocas del Toro, Panama';

UPDATE challenges SET description_en = 'Cape Verde sees Atlantic blue marlin migration November–February. Mid-ocean archipelago and wahoo and dorado make it a unique Atlantic destination. Selected for our World 100 as the Atlantic''s mid-ocean billfish capital.' WHERE category = 'fishing' AND title_en = 'Cape Verde Islands';

UPDATE challenges SET description_en = 'Ireland''s River Moy has the highest rod catch of any Irish river. Ballina in County Mayo sees prolific salmon July–September. Selected for our World 100 as Ireland''s greatest salmon river.' WHERE category = 'fishing' AND title_en = 'River Moy, Ireland';

UPDATE challenges SET description_en = 'Connemara in Ireland offers wild brown trout on limestone loughs. Galway and the mayfly season in May define Irish stillwater fishing. Selected for our World 100 as the finest Irish lough trout fishery.' WHERE category = 'fishing' AND title_en = 'Connemara, Ireland';

UPDATE challenges SET description_en = 'Finland''s Lake Inari in Lapland holds Arctic grayling and perch—August–September prime. Ice fishing in winter for brown trout. Selected for our World 100 as the premier Arctic European lake fishery.' WHERE category = 'fishing' AND title_en = 'Lake Inari, Finland';

UPDATE challenges SET description_en = 'Sweden''s Lake Vänern is the EU''s largest lake—Swedish record sea trout and pike. Near Gothenburg, it offers diverse freshwater fishing. Selected for our World 100 as Scandinavia''s greatest lake fishery.' WHERE category = 'fishing' AND title_en = 'Lake Vänern, Sweden';

UPDATE challenges SET description_en = 'Poland''s Bug River on the Belarus border holds trophy pike in lowland rivers. Pike, perch, and bream in a historic waterway. Selected for our World 100 as Central Europe''s premier pike river.' WHERE category = 'fishing' AND title_en = 'Bug River, Poland';

UPDATE challenges SET description_en = 'Italy''s Po River in the Po Valley holds monster wels catfish—250 kg records from Cremona and Mantua. Selected for our World 100 as Europe''s greatest catfish river.' WHERE category = 'fishing' AND title_en = 'Po River, Italy';

UPDATE challenges SET description_en = 'Russia''s Volga Delta at Astrakhan holds giant zander and asp; the Caspian mouth once held beluga sturgeon. Selected for our World 100 as the greatest river delta fishery in Europe.' WHERE category = 'fishing' AND title_en = 'Volga River Delta, Russia';

UPDATE challenges SET description_en = 'South Africa''s Cape Point and False Bay offer yellowfin tuna and snoek. Cold Benguela upwelling creates rich waters. Selected for our World 100 as South Africa''s premier tuna and coastal fishery.' WHERE category = 'fishing' AND title_en = 'Cape Point, South Africa';

UPDATE challenges SET description_en = 'Lake Victoria in Kenya holds Nile perch to 100 kg—Africa''s largest lake. Kisumu is the base; endemic cichlids face habitat crisis. Selected for our World 100 as the greatest African lake fishery.' WHERE category = 'fishing' AND title_en = 'Lake Victoria, Kenya';

UPDATE challenges SET description_en = 'Lake Malawi holds tigerfish and endemic cichlids. Nkhata Bay and crystal-clear waters define this Rift Valley lake. Selected for our World 100 as the most biodiverse freshwater fishery.' WHERE category = 'fishing' AND title_en = 'Lake Malawi, Malawi';

UPDATE challenges SET description_en = 'Mozambique''s Niassa Reserve offers vundu catfish and tigerfish on the Lugenda River. Fly-camp-only access to remote wilderness. Selected for our World 100 as the most remote African river fishery.' WHERE category = 'fishing' AND title_en = 'Niassa Reserve, Mozambique';

UPDATE challenges SET description_en = 'Namibia''s Walvis Bay benefits from cold Benguela upwelling—offshore tuna and kabeljou. Skeleton Coast richness. Selected for our World 100 as the premier Namibian offshore fishery.' WHERE category = 'fishing' AND title_en = 'Walvis Bay, Namibia';

UPDATE challenges SET description_en = 'Western Australia''s Ningaloo Reef—World Heritage site—offers sailfish and queenfish April–June. Coral reef and bluewater combine. Selected for our World 100 as Australia''s premier reef and billfish destination.' WHERE category = 'fishing' AND title_en = 'Ningaloo Reef, Australia';

UPDATE challenges SET description_en = 'India''s Andaman Islands in the Bay of Bengal offer offshore big game—dogtooth tuna, GT. Port Blair is the gateway to remote waters. Selected for our World 100 as India''s finest offshore island fishery.' WHERE category = 'fishing' AND title_en = 'Andaman Islands, India';

UPDATE challenges SET description_en = 'Kerala''s backwaters offer traditional cast-net fishing and houseboat life on Vembanad Lake. Alappuzha is the heart of backwater culture. Selected for our World 100 as the most cultural and unique Indian fishery.' WHERE category = 'fishing' AND title_en = 'Kerala Backwaters, India';

UPDATE challenges SET description_en = 'Vietnam''s Mekong Delta offers river monster fishing—snakehead, catfish, barb. Can Tho and the floating markets define river culture. Selected for our World 100 as the greatest Mekong Delta fishery.' WHERE category = 'fishing' AND title_en = 'Mekong Delta, Vietnam';

UPDATE challenges SET description_en = 'Japan''s Lake Biwa is the country''s largest lake—largemouth bass records and black bass tournaments. Shiga Prefecture. Selected for our World 100 as Japan''s premier bass fishery.' WHERE category = 'fishing' AND title_en = 'Lake Biwa, Japan';

UPDATE challenges SET description_en = 'Tonga in the South Pacific offers yellowfin tuna and wahoo—Ha''apai remote bluewater and deep-drop bottom fishing. Selected for our World 100 as the premier Polynesian offshore fishery.' WHERE category = 'fishing' AND title_en = 'Tonga, South Pacific';

UPDATE challenges SET description_en = 'Christmas Island in Kiribati is a bonefish and giant trevally paradise—Indo-Pacific remote flats, 10 kg GT on fly. Selected for our World 100 as the most remote Pacific flats destination.' WHERE category = 'fishing' AND title_en = 'Christmas Island, Kiribati';

UPDATE challenges SET description_en = 'New Caledonia has the Pacific''s largest lagoon (UNESCO)—coral trout and GT. Noumea offshore and lagoon fishing. Selected for our World 100 as the finest Pacific lagoon and reef fishery.' WHERE category = 'fishing' AND title_en = 'New Caledonia';

