UPDATE challenges SET description_en = 'Fernando de Noronha in Brazil is UNESCO-listed—spinner dolphins, sea turtles, and pristine Atlantic archipelago. Selected for our World 100 as Brazil''s greatest island paradise.' WHERE category = 'islands' AND title_en = 'Fernando de Noronha, Brazil';

